import collections

class Solution:
    def groupStrings(self, strings: list[str]) -> list[list[str]]:
        groups = collections.defaultdict(list)

        def get_canonical_form(s: str) -> str:
            if not s:
                return ""

            # Calculate the shift needed to make the first character 'a'
            # Example: if s[0] is 'b', shift is 1. If s[0] is 'z', shift is 25.
            shift = ord(s[0]) - ord('a')

            canonical_chars = []
            for char_code in map(ord, s):
                # Apply the calculated shift
                shifted_char_code = char_code - shift

                # Handle wrap-around for characters that go below 'a'
                # If 'a' (0) - 1 results in -1, adding 26 makes it 25 ('z').
                if shifted_char_code < ord('a'):
                    shifted_char_code += 26

                canonical_chars.append(chr(shifted_char_code))

            return "".join(canonical_chars)

        for s in strings:
            key = get_canonical_form(s)
            groups[key].append(s)

        return list(groups.values())
